import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { ToastContainer } from 'react-toastify';
import { handleError, handleSuccess } from '../utils';
import './Login.css';
import FoodImage from '../pages/1.png';
import SecurityImage from '../pages/2.jpg';

import { FaEnvelope, FaTimes } from 'react-icons/fa';

function Login() {
  const [loginInfo, setLoginInfo] = useState({ email: '', password: '' });
  const [showModal, setShowModal] = useState(false);
  const [resetEmail, setResetEmail] = useState('');
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setLoginInfo((prev) => ({ ...prev, [name]: value }));
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    const { email, password } = loginInfo;
    if (!email || !password) return handleError('Email and password are required');

    try {
      console.log("📤 Sending login info:", loginInfo);

      const response = await fetch('http://localhost:5001/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(loginInfo),
      });

      const result = await response.json();
      console.log("🔐 Server response:", result);

      const { success, message, jwtToken, name, role, _id, error } = result;

      if (success) {
        handleSuccess(message);
        localStorage.setItem('token', jwtToken);
        localStorage.setItem('loggedInUser', name);
        localStorage.setItem('userRole', role);
        localStorage.setItem('loggedInUserId', _id);
        localStorage.setItem('email', email);  // ✅ Stockage de l'email dans localStorage

        console.log("✅ User email stored in localStorage:", email);

        setTimeout(() => {
          if (role === 'business') {
            navigate('/homebusiness');
          } else if (role === 'admin') {
            navigate('/DashboardHome');
          } else {
            navigate('/user/:activepage');
          }
        }, 1000);
      } else {
        handleError(error?.details?.[0]?.message || message);
      }
    } catch (err) {
      console.log("❌ Login error:", err.message);
      handleError(err.message);
    }
  };

  return (
    <div className="login-container">
      <div className="login-box">
        <div className="login-image">
          <img src={FoodImage} alt="Food Illustration" />
        </div>
        <div className="login-form">
          <h2>Login to Account</h2>
          <p>Please enter your email and password to continue</p>
          <form onSubmit={handleLogin}>
            <div className="form-group">
              <label>Email Address</label>
              <input
                type="email"
                name="email"
                placeholder="Email Address"
                value={loginInfo.email}
                onChange={handleChange}
                className="form-control"
              />
            </div>
            <div className="form-group">
              <label>Password</label>
              <input
                type="password"
                name="password"
                placeholder="Password"
                value={loginInfo.password}
                onChange={handleChange}
                className="form-control"
              />
            </div>
            <button type="submit" className="btn btn-primary login-btn">
              Sign In
            </button>
            <p className="create-account">
              Don't have an account? <Link to="/signup">Create Account</Link>
            </p>
          </form>
        </div>
      </div>
      <ToastContainer />
    </div>
  );
}

export default Login;
